CREATE TABLE IF NOT EXISTS "AppSession" ("id" TEXT PRIMARY KEY, "tokenHash" TEXT NOT NULL UNIQUE, "userId" TEXT NOT NULL, "userAgent" TEXT, "ipHash" TEXT, "expiresAt" TIMESTAMP(3) NOT NULL, "lastUsedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS "AppSession_userId_idx" ON "AppSession"("userId");
CREATE INDEX IF NOT EXISTS "AppSession_expiresAt_idx" ON "AppSession"("expiresAt");
CREATE TABLE IF NOT EXISTS "OnlinePayment" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL, "planId" TEXT NOT NULL, "subscriptionId" TEXT, "provider" TEXT NOT NULL, "providerPaymentId" TEXT, "providerCheckoutId" TEXT, "providerEventId" TEXT, "method" TEXT NOT NULL, "originalAmountInCents" INTEGER NOT NULL, "discountInCents" INTEGER NOT NULL DEFAULT 0, "amountInCents" INTEGER NOT NULL, "currency" TEXT NOT NULL DEFAULT 'BRL', "status" TEXT NOT NULL DEFAULT 'pending', "pixQrCode" TEXT, "pixQrCodeBase64" TEXT, "pixCopyPaste" TEXT, "pixTicketUrl" TEXT, "pixExpiresAt" TIMESTAMP(3), "cardBrand" TEXT, "cardLastFour" TEXT, "installments" INTEGER, "paidAt" TIMESTAMP(3), "expiresAt" TIMESTAMP(3), "refundedAmountInCents" INTEGER NOT NULL DEFAULT 0, "idempotencyKey" TEXT NOT NULL UNIQUE, "renewalMode" TEXT NOT NULL DEFAULT 'extend', "providerPayload" JSONB, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS "OnlinePayment_userId_createdAt_idx" ON "OnlinePayment"("userId", "createdAt");
CREATE INDEX IF NOT EXISTS "OnlinePayment_provider_providerPaymentId_idx" ON "OnlinePayment"("provider", "providerPaymentId");
CREATE INDEX IF NOT EXISTS "OnlinePayment_status_idx" ON "OnlinePayment"("status");
CREATE TABLE IF NOT EXISTS "OnlineSubscription" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL UNIQUE, "planId" TEXT NOT NULL, "provider" TEXT NOT NULL, "providerSubscriptionId" TEXT, "paymentMethod" TEXT NOT NULL, "planName" TEXT NOT NULL, "planPriceInCents" INTEGER NOT NULL, "durationDays" INTEGER NOT NULL, "status" TEXT NOT NULL DEFAULT 'pending', "startedAt" TIMESTAMP(3), "expiresAt" TIMESTAMP(3), "nextBillingAt" TIMESTAMP(3), "cancelledAt" TIMESTAMP(3), "autoRenew" BOOLEAN NOT NULL DEFAULT false, "cardBrand" TEXT, "cardLastFour" TEXT, "graceUntil" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS "OnlineSubscription_provider_providerSubscriptionId_idx" ON "OnlineSubscription"("provider", "providerSubscriptionId");
CREATE INDEX IF NOT EXISTS "OnlineSubscription_status_idx" ON "OnlineSubscription"("status");
CREATE TABLE IF NOT EXISTS "PaymentWebhookEvent" ("id" TEXT PRIMARY KEY, "provider" TEXT NOT NULL, "providerEventId" TEXT NOT NULL, "eventType" TEXT NOT NULL, "resourceId" TEXT, "payloadHash" TEXT NOT NULL, "processedAt" TIMESTAMP(3), "status" TEXT NOT NULL DEFAULT 'received', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "PaymentWebhookEvent_provider_providerEventId_key" UNIQUE ("provider", "providerEventId"));
CREATE TABLE IF NOT EXISTS "PaymentAuditLog" ("id" TEXT PRIMARY KEY, "userId" TEXT, "actorId" TEXT, "action" TEXT NOT NULL, "entityId" TEXT, "details" JSONB, "risk" TEXT NOT NULL DEFAULT 'medium', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS "PaymentAuditLog_userId_createdAt_idx" ON "PaymentAuditLog"("userId", "createdAt");
CREATE INDEX IF NOT EXISTS "PaymentAuditLog_action_idx" ON "PaymentAuditLog"("action");
